#!/bin/bash
apt update && apt install -y unzip jq ufw && bash <(curl -Ls https://raw.githubusercontent.com/XTLS/Xray-install/main/install-release.sh) && mkdir -p /usr/local/etc/xray && echo "" | base64 -d > /usr/local/etc/xray/config.json && echo "" | base64 -d > /usr/local/bin/v2ray-node-add-vless && echo "" | base64 -d > /usr/local/bin/v2ray-node-add-out && chmod +x /usr/local/bin/v2ray-node-add-vless /usr/local/bin/v2ray-node-add-out && ufw disable && systemctl restart xray && echo "✅ SUCCESS: New Node Ready!" && systemctl status xray --no-pager | grep Active
